import{c as o,Z as a,Q as n,j as r,o as i,m as l}from"./chunks/framework.qjzPVSkb.js";const m=JSON.parse('{"title":"Token","description":"AI 模型处理文本的最小单位，同时是计费和上下文窗口的计数标准","frontmatter":{"title":"Token","description":"AI 模型处理文本的最小单位，同时是计费和上下文窗口的计数标准","difficulty":"beginner"},"headers":[],"relativePath":"terms/token.md","filePath":"terms/token.md"}'),d={name:"terms/token.md"};function s(c,e,h,k,u,p){const t=a("DifficultyBadge");return n(),r("div",null,[i(t,{level:"beginner"}),e[0]||(e[0]=l('<h1 id="token" tabindex="-1">Token <a class="header-anchor" href="#token" aria-label="Permalink to &quot;Token&quot;">​</a></h1><p>Token 是使用 AI 模型时最基础但也最容易混淆的概念。它同时扮演<strong>输入单位、计费单位、容量单位</strong>三个角色。</p><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>Token 是 LLM 处理文本的最小粒度。一句话先被切分成 Token，模型再逐个处理和生成。中文大约 1 个字 = 1~2 个 Token，英文大约 1 个单词 = 1~2 个 Token。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>把一段文字想象成一幅乐高积木作品。Token 就是<strong>被拆开后的每一块乐高</strong>：</p><ul><li>&quot;我爱 AI&quot; → 拆成 3~4 个 Token（<code>我</code> <code>爱</code> <code>AI</code> 或 <code>AI</code>拆分）</li><li>&quot;I love AI&quot; → 拆成 3~4 个 Token（<code>I</code> <code>love</code> <code>AI</code>）</li></ul><p>模型读你的提示词时，是把 Token 一块块&quot;吃&quot;进去的；输出回答时，也是一块块&quot;吐&quot;出来的。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>Tokenization 是文本预处理的第一步。不同模型使用不同的分词器（Tokenizer）：</p><ul><li><strong>GPT 系列</strong>：使用 BPE（Byte Pair Encoding），将常见词作为整体，罕见词拆为子词</li><li><strong>中文模型</strong>：通常以字或词为粒度，配合 BPE 处理英文混合文本</li></ul><p>一个实用经验：<strong>1000 Token ≈ 750 个英文单词 ≈ 400~500 个汉字</strong>。</p><p>Token 的三个关键用途：</p><table tabindex="0"><thead><tr><th>用途</th><th>说明</th></tr></thead><tbody><tr><td>输入计数</td><td>模型能处理的 Token 上限由上下文窗口决定</td></tr><tr><td>输出计数</td><td>模型生成回答消耗 Token，每次 API 调用都有输出限制</td></tr><tr><td>计费基础</td><td>API 按输入/输出 Token 数分别计费，输出通常更贵</td></tr></tbody></table><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/context-window.html">上下文窗口</a> —— 单次对话能容纳的 Token 总量</li><li><a href="/ai-knowledge/terms/prompt.html">Prompt</a> —— 你给模型的 Token 输入</li></ul><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://platform.openai.com/tokenizer" target="_blank" rel="noreferrer">OpenAI Tokenizer 在线工具</a> —— 亲自试试文字是怎么被切成 Token 的</li><li><a href="https://huggingface.co/docs/tokenizers/index" target="_blank" rel="noreferrer">Hugging Face Tokenizers 文档</a></li></ul>',18))])}const f=o(d,[["render",s]]);export{m as __pageData,f as default};
